def base_convert(num: str, from_base: int, to_base: int) -> str:
    # Validate bases
    if not (2 <= from_base <= 36) or not (2 <= to_base <= 36):
        raise ValueError(f"Base must be between 2 and 36")

    # Handle empty string
    if not num:
        raise ValueError("Empty string is not valid")

    # Handle sign
    negative = False
    s = num
    if s[0] == '-':
        negative = True
        s = s[1:]

    if not s:
        raise ValueError("No digits after sign")

    # Convert from from_base to integer
    def char_to_val(c):
        c = c.lower()
        if '0' <= c <= '9':
            v = ord(c) - ord('0')
        elif 'a' <= c <= 'z':
            v = ord(c) - ord('a') + 10
        else:
            raise ValueError(f"Invalid character: {c!r}")
        if v >= from_base:
            raise ValueError(f"Digit {c!r} is invalid for base {from_base}")
        return v

    # Convert to integer value
    value = 0
    for c in s:
        value = value * from_base + char_to_val(c)

    # Convert integer to to_base
    def int_to_base(n, base):
        if n == 0:
            return '0'
        digits = []
        while n > 0:
            digits.append(n % base)
            n //= base
        digits.reverse()
        chars = '0123456789abcdefghijklmnopqrstuvwxyz'
        return ''.join(chars[d] for d in digits)

    result = int_to_base(value, to_base)

    # Remove leading zeros (shouldn't happen but just in case)
    result = result.lstrip('0') or '0'

    if negative and result != '0':
        result = '-' + result

    return result

